"use client";

import { useEffect, useState, useRef } from 'react';
import { motion, useInView } from 'framer-motion';
import { Users, Briefcase, Globe2, Award } from 'lucide-react';

interface Stat {
  icon: any;
  value: number;
  suffix: string;
  label: string;
}

const stats: Stat[] = [
  { icon: Users, value: 500, suffix: '+', label: 'Happy Clients' },
  { icon: Briefcase, value: 1200, suffix: '+', label: 'Projects Completed' },
  { icon: Globe2, value: 45, suffix: '+', label: 'Countries Served' },
  { icon: Award, value: 98, suffix: '%', label: 'Success Rate' },
];

const AnimatedNumber = ({ value, suffix }: { value: number; suffix: string }) => {
  const [count, setCount] = useState(0);
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: "-50px" });

  useEffect(() => {
    if (!isInView) return;
    let start = 0;
    const end = value;
    const duration = 2000;
    const increment = end / (duration / 16);

    const timer = setInterval(() => {
      start += increment;
      if (start >= end) {
        setCount(end);
        clearInterval(timer);
      } else {
        setCount(Math.floor(start));
      }
    }, 16);
    return () => clearInterval(timer);
  }, [isInView, value]);

  return (
    <span ref={ref} className="tabular-nums tracking-tighter">
      {count.toLocaleString()}{suffix}
    </span>
  );
};

export const StatsCounter = () => {
  return (
    <section className="py-12 md:py-20 lg:py-24 relative overflow-hidden bg-white">
      {/* Background Blobs - Sizes adjusted for better screen scaling */}
      <div className="absolute top-0 left-1/4 w-48 h-48 md:w-96 md:h-96 bg-cyan-100/40 rounded-full blur-[80px] md:blur-[120px] -z-10 animate-pulse" />
      <div className="absolute bottom-0 right-1/4 w-48 h-48 md:w-96 md:h-96 bg-blue-100/40 rounded-full blur-[80px] md:blur-[120px] -z-10" />

      <div className="container mx-auto px-4 lg:px-8 relative z-10 max-w-7xl">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
          className="text-center mb-12 md:mb-16 lg:mb-20"
        >
          <motion.div 
            initial={{ opacity: 0, scale: 0.9 }}
            whileInView={{ opacity: 1, scale: 1 }}
            className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-slate-50 border border-slate-200 text-[#003366] text-[10px] md:text-xs font-bold uppercase tracking-widest mb-4 md:mb-6 shadow-sm"
          >
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-cyan-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-cyan-500"></span>
            </span>
            Our Impact
          </motion.div>

          {/* Responsive Heading - Balanced for LG screens */}
          <h2 className="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-black text-slate-900 tracking-tight mb-4 md:mb-6 leading-tight lg:leading-[1.1]">
            Delivering <span className="text-transparent bg-clip-text bg-gradient-to-r from-[#003366] via-[#004d99] to-cyan-500">
              Exceptional Results
            </span>
          </h2>

          <p className="text-slate-500 max-w-2xl mx-auto text-base md:text-lg lg:text-xl leading-relaxed font-medium px-4">
            Our track record speaks for itself. We don't just build software; 
            we engineer <span className="text-slate-900">growth and global reach.</span>
          </p>

          <motion.div
            initial={{ width: 0 }}
            whileInView={{ width: "60px md:width: 80px" }}
            transition={{ delay: 0.4, duration: 0.8 }}
            className="h-1.5 bg-gradient-to-r from-[#003366] to-cyan-400 mx-auto mt-6 md:mt-10 rounded-full"
          />
        </motion.div>

        {/* Responsive Grid: 1 col on mobile, 2 on tablet, 4 on desktop */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6 lg:gap-8 items-stretch">
          {stats.map((stat, index) => (
            <motion.div
              key={stat.label}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1, duration: 0.5 }}
              whileHover={{ y: -5 }}
              className="relative group h-full"
            >
              <div className="relative overflow-hidden p-6 md:p-8 rounded-[1.5rem] md:rounded-[2.5rem] bg-white border border-slate-100 hover:border-cyan-200 transition-all duration-300 hover:shadow-xl shadow-sm h-full flex flex-col items-center text-center">
                
                {/* Icon Orb - Responsive size */}
                <div className="relative w-14 h-14 md:w-16 md:h-16 lg:w-20 lg:h-20 rounded-2xl md:rounded-3xl bg-gradient-to-br from-slate-50 to-slate-100 flex items-center justify-center mb-4 md:mb-6 group-hover:rotate-[5deg] transition-transform duration-500 border border-white shadow-inner">
                  <stat.icon className="w-6 h-6 md:w-8 md:h-8 lg:w-10 lg:h-10 text-[#003366]" />
                </div>

                {/* Responsive Stat Number */}
                <div className="text-3xl sm:text-4xl md:text-5xl lg:text-5xl font-black mb-2 text-slate-900 tracking-tighter group-hover:text-[#003366] transition-colors duration-300">
                  <AnimatedNumber value={stat.value} suffix={stat.suffix} />
                </div>

                <p className="text-slate-400 font-bold uppercase text-[10px] md:text-xs tracking-widest">{stat.label}</p>

                {/* Bottom Bar - Mobile Optimized */}
                <div className="absolute bottom-0 inset-x-0 h-1 md:h-1.5 bg-slate-50 group-hover:bg-gradient-to-r group-hover:from-[#003366] group-hover:to-cyan-500 transition-all duration-300" />
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};